#!/usr/local/bin/python3.13"""    procvw is a process viewer developed for FreeBSD.    Copyright (C) 2026  Markus Johnsson a.k.a. FerusX.Swe    All rights reserved.    This program is free software: you can redistribute it and/or modify    it under the terms of the GNU General Public License as published by    the Free Software Foundation, either version 3 of the License, or    (at your option) any later version.    This program is distributed in the hope that it will be useful,    but WITHOUT ANY WARRANTY; without even the implied warranty of    MERCHANTABILITY or FITNESS FOR A PARTICULAR PURPOSE.  See the    GNU General Public License for more details.    For the GNU General Public License, see <https://www.gnu.org/licenses/>."""import argparseimport sysimport json# Local importsfrom fetcher import ProcessFetcherfrom filters import ProcessFilter, ProcessSorterfrom printer import ProcessPrinterfrom tree_builder import ProcessTreeBuilderfrom formatter import ProcessFormatterfrom tree_formatter import ProcessTreeFormatterfrom utils import (    load_json_processes,    build_tree_json,    print_summary, limit_tree_nodes)# =========================================================# Class: CustomArgumentParser# =========================================================class CustomArgumentParser(argparse.ArgumentParser):    """    Custom argument parser that overrides the default exit behavior.    Purpose:        Prevent argparse from terminating the program abruptly with sys.exit()        when encountering errors or help messages.    Behavior:        - Prints the error/help message to stderr (if present)        - Raises SystemExit manually instead of exiting internally    Why:        This allows better control over program flow and makes it possible        to handle argument parsing errors more cleanly, especially in tools        where you may want to intercept or customize exit behavior.    """    def exit(self, status=0, message=None):        """        Override of argparse.ArgumentParser.exit().        Instead of calling sys.exit() directly, this method:        - Prints the message (if any)        - Raises SystemExit with the given status        Args:            status (int): Exit status code            message (str, optional): Message to print before exiting        """        if message:            self._print_message(message, sys.stderr)        raise SystemExit(status)# =========================================================# Main App# =========================================================class ProcVwApp:    """    Main application controller for procvw.    Manages the full processing pipeline:        Fetch → Filter → Sort → Format → Print    Responsibilities:        - Parse command-line arguments        - Coordinate data flow between components        - Select output mode (table or tree)    This class contains no heavy logic itself — it delegates all work    to specialized components.    """    # ---------------------------------------------------------------------    # __init__    # ---------------------------------------------------------------------    def __init__(self):        """        Initialize the application and parse CLI arguments.        """        self.args = self._parse_args()        # Validate flags        self._validate_args()    # ---------------------------------------------------------------------    # Method: _parse_args    # ---------------------------------------------------------------------    def _parse_args(self):        """        Define and parse command-line arguments.        Returns:            argparse.Namespace: Parsed CLI arguments        Supported options:            - Filtering: --user, --pid, --cmd-filter            - Sorting: --sort, --bottom            - Output: --number, --color, --json            - View modes: --tree, --table, --json-view            - Tree enhancements: --cpu-all, --cpu-threshold, --tree-depth            - File: --save, --load            - General: --all        """        parser = CustomArgumentParser(            prog="procvw",            description="BSD Process Viewer",            formatter_class=argparse.RawTextHelpFormatter        )        parser.add_argument(            "--all",            action="store_true",            help="Include kernel/system processes"        )        parser.add_argument(            "-b",            "--bottom",            action="store_true"        )        parser.add_argument(            "--charset",            choices=["ascii", "utf8"],            default="utf-8",            help="Use ASCII in tree mode"        )        parser.add_argument(            "--color",            action="store_true"        )        parser.add_argument(            "--cpu-all",            action="store_true",            help="Show subtree CPU usage for all nodes (tree mode)"        )        parser.add_argument(            "--cpu-threshold",            type=float,            help="Show subtree CPU only for nodes above threshold"        )        parser.add_argument(            "-f",            "--cmd-filter"        )        parser.add_argument(            '-g',            "--glyph-style",            choices=["1", "2", "3"],            default=None,            help="Changes the glyph style in tree mode"        )        parser.add_argument(            "--json",            action="store_true",            help="Output process data in JSON format"        )        parser.add_argument(            "-w",            "--line-wrap",            action="store_true",            help="Allow long COMMAND fields to wrap instead of being truncated"        )        parser.add_argument(            "--load",            metavar="FILE",            help="Load process tree from JSON file instead of live system"        )        parser.add_argument(            "--no-header",            action="store_true",            help="Do not display column headers plus line"        )        parser.add_argument(            "-n",            "--number",            type=int,            default=20        )        parser.add_argument(            "-p",            "--pid",            type=int        )        parser.add_argument(            "--save",            metavar="FILE",            help="Save output to JSON file"        )        parser.add_argument(            "-s",            "--sort",            choices=["cpu", "mem", "pid", "rss", "cmd", "thr"],            default="cpu"        )        parser.add_argument(            "-u",            "--user"        )        parser.add_argument(            "--table",            action="store_true",            help="Display processes in table view"        )        parser.add_argument(            "--tree",            action="store_true",            help="Display processes in tree view"        )        parser.add_argument(            "--tree-depth",            type=int,            help="Limit tree depth (1 = root only)"        )        parser.add_argument(            "--show-path",            action="store_true",            help="Show full command with arguments (tree mode only)"        )        parser.add_argument(            "--raw",            action="store_true",            help="Output raw, unformatted process data (no colors, no alignment)"        )        return parser.parse_args()    # ---------------------------------------------------------------------    # Method: _validate_args    # ---------------------------------------------------------------------    def _validate_args(self):        """ Validate arguments """        # Tree mode plus JSON        if self.args.tree and self.args.json:            raise SystemExit("Error: --tree and --json cannot be used together")        # Table vs tree view        if self.args.table and self.args.tree:            raise SystemExit("Error: Cannot use --table and --tree together")        # CPU-flags plus depth flag        if self.args.table:            if self.args.tree_depth is not None:                raise SystemExit("Error: --tree-depth is only valid with --tree")        # Sorting issues        valid_sort = {"cpu", "mem", "pid", "rss", "thr", "cmd"}        if self.args.sort not in valid_sort:            raise SystemExit(f"Error: Invalid sort key: {self.args.sort}")        # CPU threshold sanity        if self.args.cpu_threshold is not None and self.args.cpu_threshold < 0:            raise SystemExit("Error: --cpu-threshold must be >= 0")        # Tree-depth sanity        if self.args.tree_depth is not None and self.args.tree_depth < 1:            raise SystemExit("Error: --depth must be >= 1")        # Table mode vs glyph style        if self.args.table and not self.args.load:            raise SystemExit("Error: --table should only be used with --load")        # Glyph style vs not using tree mode        if self.args.glyph_style is not None and not self.args.tree:            raise SystemExit("Error: --glyph-style is only valid with --tree")        # On load JSON        if self.args.load:            if not self.args.load.endswith(".json"):                raise SystemExit("Error: --load expects a .json file")        # Line wrap vs tree mode        if self.args.tree and self.args.line_wrap:            raise SystemExit("Error: --line-wrap is not supported in --tree mode")        # Color vs raw        if self.args.raw and self.args.color:            raise SystemExit("Error: --color cannot be used with --raw")    # ---------------------------------------------------------------------    # Method: run    # ---------------------------------------------------------------------    def run(self):        """        Execute the application pipeline.        Flow:            1. Fetch processes from system            2. Apply filters (user, pid, command)            3. Sort processes            4. Render output (tree or table)            5. Print results to terminal        Notes:            - Tree mode requires a full process list to preserve hierarchy            - Standard mode limits output to --number entries        """        saved_file = None        loaded_file = None        if self.args.load:            processes = load_json_processes(self.args.load, self.args)            loaded_file = self.args.load        else:            processes = ProcessFetcher.fetch(self.args)        processes = ProcessFilter.apply(processes, self.args)        processes = ProcessSorter.apply(processes, self.args)        if self.args.save:            filename = self.args.save            # Ensure .json extension            if not filename.endswith(".json"):                filename += ".json"            saved_file = filename            # Build tree from current processed dataset            all_processes = processes            if not self.args.all:                all_processes = [                    p for p in all_processes                    if not (p.pid == 11 and "idle" in p.command.lower())                ]            roots, children = ProcessTreeBuilder.build(all_processes)            data = build_tree_json(roots, children, self.args)            try:                with open(filename, "w") as f:                    json.dump(data, f, indent=2)            except Exception as e:                raise SystemExit(f"Error saving file: {e}")        if self.args.load and not self.args.table:            self.args.tree = True        if self.args.tree:            all_processes = processes            if not self.args.all:                all_processes = [                    p for p in all_processes                    if not (p.pid == 11 and "idle" in p.command.lower())                ]            roots, children = ProcessTreeBuilder.build(all_processes)            if self.args.json:                data = build_tree_json(roots, children, self.args)                if self.args.number:                    data = limit_tree_nodes(data, self.args.number)                json_output = json.dumps(data, indent=2)                if self.args.json or not self.args.save:                    print(json_output)                # COUNT NODES                def count_nodes(nodes):                    total = 0                    for n in nodes:                        if not n:                            continue                        total += 1                        total += count_nodes(n.get("children", []))                    return total                node_count = count_nodes(data)                print_summary(node_count, self.args.color)                return            # NORMAL TREE OUTPUT (ONLY REACHED IF NOT JSON)            lines = ProcessTreeFormatter.format(                processes,                all_processes,                self.args,                self.args.color            )        else:            if self.args.number:                processes = processes[: self.args.number]            if self.args.json:                data = [                    {                        "pid": p.pid,                        "ppid": p.ppid,                        "user": p.user,                        "command": p.command,                        "cpu": p.cpu,                        "mem": p.mem,                        "rss_mb": p.rss_mb,                        "threads": p.threads,                        "started": p.started,                        "time": p.time                    }                    for p in processes                ]                json_output = json.dumps(data, indent=2)                if self.args.save:                    with open(self.args.save, "w") as f:                        f.write(json_output)                if self.args.json or not self.args.save:                    print(json_output)                return            lines = ProcessFormatter.format(processes, self.args.color, self.args)        # Print to standard output        ProcessPrinter.print(lines)        ## Print a summary line below the table/tree view telling        ## how many processes/nodes were displayed        if self.args.tree:            print_summary(len(lines), self.args.color)        else:            print_summary(len(processes), self.args.color, mode="table")        # Print a confirmation of saved/loaded processes        if saved_file:            print(f"Saved entries to {saved_file}")        if loaded_file:            print(f"Loaded entries from {loaded_file}")# =========================================================# Entry# =========================================================if __name__ == "__main__":    app = ProcVwApp()    app.run()